//-------------------------------------------------------------------------
// 물류자차위수탁 장비 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  scwin.txt_saveType = "2"; // 0:신규, 1:수정, 2:조회

  let txt_qryCntn = ed_qryCntn.getValue().trimAll();
  if (txt_qryCntn.length < 1) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_011.replace("%1", "검색어").replace("%2", "글자(숫자) 한(두)"));
    ed_qryCntn.focus();
    return false;
  }
  let vEqDelYn = "0";
  let vMbssysVehclYn = "0";
  if (cbx_eqDelYn.getValue() == "1") {
    vEqDelYn = "1";
  }
  if (cbx_mbssysVehclYn.getValue() == "1") {
    vMbssysVehclYn = "1";
  }
  ds_logisticsMcarConsignment.reform();
  let condition = "?";
  condition += "sysCls=" + acb_sysCls.getValue() + "&qryCond=" + acb_qryCond.getValue() + "&eqClssCd=" + acb_eqClssCd.getValue() + "&qryCntn=" + ed_qryCntn.getValue() + "&eqDelYn=" + vEqDelYn + "&mbssysVehclYn=" + vMbssysVehclYn;
  sbm_searchLogisticsMcarConsignment.action = "/cm.bc.eq.eqmgnt.cmd.RetrieveLogisticsMcarConsignmentEquipmentListCMD.do" + condition;
  $c.sbm.execute($p, sbm_searchLogisticsMcarConsignment);
  scwin.f_ContentsDisable();

  // $c.gus.cfDisableBtn([b_Cancel,btn_save,b_Cancel1,btn_save1])
};

