      // 화종구분 조회 팝업	

      rtnList = udc_hwajongInfo1.cfCommonPopUp(scwin.udc_hwajongInfo1_callBackFunc, pCode, pName, pClose, null, null, null, null, '2', null, null, null, null, null, pAllSearch, "화종구분조회,화종구분코드,화종구분명");

      // cfSetReturnValue(rtnList, ed_hwajong1Cd, ed_hwajong1Nm);
      break;
